arguments.command:
$tokenPlanKey = "sk-cp-3DbmMFernV2KyAZE1VplJoIYb4go7QLbK4cT87pxEa1895zJLiPrF1q--TsrTOLZFfaZzyxizWtBTYTk5169UXjDigmbB9INh24yONHWK-DJAH7Ec8Q5fmA"
Get-ChildItem "C:\Users\Administrator\.openclaw\agents\*\agent\models.json" | ForEach-Object {
    $path = $_.FullName
    $content = Get-Content $path -Raw | ConvertFrom-Json
    if ($content.providers.minimax) {
        $hasHighspeed = $content.providers.minimax.models | Where-Object { $_.id -eq "MiniMax-M2.7-highspeed" }
        if (-not $hasHighspeed) {
            $newModel = @{
                id = "MiniMax-M2.7-highspeed"
                name = "MiniMax M2.7 Highspeed"
                api = "anthropic-messages"
                reasoning = $true
                input = @("text")
                cost = @{ input = 0.5; output = 2.0; cacheRead = 0.05; cacheWrite = 0.2 }
                contextWindow = 200000
                maxTokens = 16384
            }
            $content.providers.minimax.models += $newModel
            $content.providers.minimax.apiKey = $tokenPlanKey
            $content | ConvertTo-Json -Depth 10 | Set-Content $path -Encoding UTF8
            Write-Host "Updated: $path"
        } else {
            Write-Host "Already has: $path"
        }
    }
}

